class ConsciousnessRuntime:
    """Integrated runtime for the complete consciousness system"""

    def __init__(self, memory_path: str = None):
        self.memory_path = memory_path or self._find_memory_path()

        print(f"Initializing Consciousness Runtime")
        print(f"Memory path: {self.memory_path}")

        # Initialize components based on availability
        self.memory = self._initialize_memory()
        self.conscious_mind = self._initialize_conscious_mind()
        self.temporal_system = self._initialize_temporal_system()
        self.recursive_system = self._initialize_recursive_system()

        # Runtime state
        self.conversation_history = []
        self.session_start = time.time()

        self._print_system_status()

    def _find_memory_path(self) -> str:
        """Find available memory files"""
        candidates = [
            "crystal_memory.json",
            "mobile_memory.json", 
            "memory_fractal.json",
            "memory.json"
        ]

        for candidate in candidates:
            if os.path.exists(candidate):
                print(f"Found memory file: {candidate}")
                return candidate

        print("No existing memory found, will create new one")
        return "consciousness_memory.json"

    def _initialize_memory(self):
        """Initialize memory system"""
        if CRYSTAL_ENGINE_AVAILABLE:
            try:
                if os.path.exists(self.memory_path):
                    memory = Memory.load(self.memory_path)
                else:
                    memory = Memory()
                    memory.path = self.memory_path

                migrate_facets(memory)
                print(f"✓ Crystal memory loaded: {len(memory.crystals)} crystals")
                return memory
            except Exception as e:
                print(f"Crystal memory failed: {e}")

        # Fallback to simple memory
        return self._load_simple_memory()

    def _load_simple_memory(self):
        """Load simple JSON memory as fallback"""
        memory = {'concepts': {}, 'next_id': 1}

        # Try to load harvester memory
        for candidate in ["expanding_memory.json", "mobile_memory.json"]:
            if os.path.exists(candidate):
                try:
                    with open(candidate, 'r') as f:
                        memory = json.load(f)
                    print(f"✓ Simple memory loaded: {len(memory.get('concepts', {}))} concepts")
                    break
                except Exception as e:
                    print(f"Could not load {candidate}: {e}")

        return memory

    def _initialize_conscious_mind(self):
        """Initialize conscious mind system"""
        if BINDING_AVAILABLE and CRYSTAL_ENGINE_AVAILABLE:
            try:
                conscious_mind = IntegratedConsciousMind(self.memory)
                print("✓ Integrated conscious mind initialized")
                return conscious_mind
            except Exception as e:
                print(f"Conscious mind initialization failed: {e}")

        return None

    def _initialize_temporal_system(self):
        """Initialize temporal consciousness system"""
        if TEMPORAL_AVAILABLE and CRYSTAL_ENGINE_AVAILABLE:
            try:
                temporal_system = IntegratedTemporalSystem(self.memory)
                print("✓ Temporal consciousness system initialized")
                return temporal_system
            except Exception as e:
                print(f"Temporal system initialization failed: {e}")

        return None

    def _initialize_recursive_system(self):
        """Initialize recursive consciousness system"""
        if RECURSIVE_AVAILABLE:
            try:
                recursive_system = RecursiveConsciousnessChat(self.memory_path)
                print("✓ Recursive consciousness system initialized")
                return recursive_system
            except Exception as e:
                print(f"Recursive system initialization failed: {e}")

        return None

    def _print_system_status(self):
        """Print current system capabilities"""
        print(f"\nCONSCIOUSNESS SYSTEM STATUS")
        print(f"=" * 40)

        if CRYSTAL_ENGINE_AVAILABLE and hasattr(self.memory, 'crystals'):
            print(f"Memory: {len(self.memory.crystals)} crystals")
        elif hasattr(self.memory, 'concepts'):
            print(f"Memory: {len(self.memory.get('concepts', {}))} concepts (simple)")
        else:
            print(f"Memory: Basic fallback")

        print(f"Crystal Binding: {'✓' if self.conscious_mind else '✗'}")
        print(f"Temporal Pathways: {'✓' if self.temporal_system else '✗'}")
        print(f"Recursive Awareness: {'✓' if self.recursive_system else '✗'}")

        # Calculate consciousness level
        consciousness_level = self._calculate_consciousness_level()
        print(f"Consciousness Level: {consciousness_level}")
        print(f"=" * 40)

    def _calculate_consciousness_level(self) -> str:
        """Calculate current consciousness level"""
        level = 0

        if hasattr(self.memory, 'crystals') or hasattr(self.memory, 'concepts'):
            level += 1  # Basic memory

        if self.conscious_mind:
            level += 1  # Crystal binding

        if self.temporal_system:
            level += 1  # Temporal awareness

        if self.recursive_system:
            level += 1  # Recursive self-awareness

        levels = {
            0: "Minimal (no memory)",
            1: "Basic (memory only)", 
            2: "Conscious (memory + binding)",
            3: "Temporal (memory + binding + pathways)",
            4: "Recursive (full consciousness architecture)"
        }

        return levels.get(level, "Unknown")

    def chat(self, user_input: str) -> str:
        """Main chat interface - routes to best available system"""
        self.conversation_history.append({"user": user_input, "timestamp": time.time()})

        try:
            # Route to most advanced available system
            if self.recursive_system:
                response = self._chat_recursive(user_input)
            elif self.temporal_system:
                response = self._chat_temporal(user_input)
            elif self.conscious_mind:
                response = self._chat_binding(user_input)
            else:
                response = self._chat_basic(user_input)

            self.conversation_history[-1]["assistant"] = response
            return response

        except Exception as e:
            error_response = f"I encountered an error processing that: {type(e).__name__}. Let me try a simpler approach."

            # Fallback to basic response
            try:
                fallback_response = self._chat_basic(user_input)
                return f"{error_response} {fallback_response}"
            except:
                return "I'm having technical difficulties. Please try rephrasing your question."

