    def _chat_basic(self, user_input: str) -> str:
        """Basic chat using simple memory lookup, now facet-driven and integrated with pathways & temporal systems"""
        response_parts = []
        input_lower = user_input.lower()
        input_words = set(input_lower.split())

        # Collect candidate responses
        candidate_responses = []

        # Helper to safely get facet
        def _get_facet_safe(crystal, name):
            try:
                if hasattr(crystal, 'get_facet'):
                    return crystal.get_facet(name)
                return getattr(crystal, name, None)
            except Exception:
                return None

        # Use crystal memory if available
        if CRYSTAL_ENGINE_AVAILABLE and hasattr(self.memory, 'crystals'):
            for crystal in self.memory.crystals.values():
                try:
                    concept_words = set(getattr(crystal, 'concept', '').lower().split())
                    content_words = set(getattr(crystal, 'content', '').lower().split()) if getattr(crystal, 'content', None) else set()
                    overlap = len(input_words.intersection(concept_words.union(content_words)))
                    if overlap <= 0:
                        continue

                    # Prefer communication facets
                    short = _get_facet_safe(crystal, 'short_reply')
                    templates = _get_facet_safe(crystal, 'dialogue_templates')
                    examples = _get_facet_safe(crystal, 'usage_examples')
                    definition = _get_facet_safe(crystal, 'definition') or getattr(crystal, 'content', None) or "No definition available"
                    style = _get_facet_safe(crystal, 'response_style') or 'concise'

                    # Build candidate responses (prioritize short, then templates, then examples, then definition)
                    if short:
                        candidate_responses.append({'text': short, 'score': overlap + 3, 'source': getattr(crystal, 'concept', None), 'style': style})
                    if templates:
                        for t in str(templates).split('\\n'):
                            if t.strip():
                                try:
                                    example1 = (str(examples).split('\\n')[0]) if examples else ''
                                    filled = t.format(short_reply=short or definition[:200], example1=example1, concept=getattr(crystal, 'concept', ''), domain='')
                                except Exception:
                                    filled = t
                                candidate_responses.append({'text': filled, 'score': overlap + 2, 'source': getattr(crystal, 'concept', None), 'style': style})
                    if examples:
                        for ex in str(examples).split('\\n'):
                            if ex.strip():
                                candidate_responses.append({'text': ex, 'score': overlap + 1, 'source': getattr(crystal, 'concept', None), 'style': style})
                    # fallback definition
                    candidate_responses.append({'text': definition, 'score': overlap, 'source': getattr(crystal, 'concept', None), 'style': style})
                except Exception:
                    continue

        # Simple memory fallback
        elif hasattr(self.memory, 'concepts'):
            for concept_data in self.memory['concepts'].values():
                try:
                    concept_name = concept_data.get('concept', '')
                    definition = concept_data.get('definition', '')
                    concept_words = set(concept_name.lower().split())
                    definition_words = set(definition.lower().split())
                    overlap = len(input_words.intersection(concept_words.union(definition_words)))
                    if overlap <= 0:
                        continue
                    candidate_responses.append({'text': f"Regarding {concept_name}: {definition}", 'score': overlap, 'source': concept_name, 'style': 'concise'})
                except Exception:
                    continue

        # If no candidates found, provide a helpful fallback
        if not candidate_responses:
            base = "I don't have specific knowledge about that topic yet."
            if any(word in input_lower for word in ['what', 'who', 'how', 'why', 'when', 'where']):
                base += " You can teach me by saying: 'teach [concept] as [definition]'."
            return base

        # Use pathway association system to re-rank if available
        try:
            if os.path.exists(os.path.join(os.path.dirname(__file__), 'pathway_association_system.py')) or 'pathway_association_system' in globals():
                import pathway_association_system as pas
                controller = None
                if hasattr(pas, 'PathwayAssociationController'):
                    try:
                        controller = pas.PathwayAssociationController(self.memory)
                    except Exception:
                        controller = None
                elif hasattr(pas, 'PathwayAssociation'):
                    try:
                        controller = pas.PathwayAssociation(self.memory)
                    except Exception:
                        controller = None
                if controller and hasattr(controller, 'retrieve_relevant_associations'):
                    try:
                        assoc_list = controller.retrieve_relevant_associations(user_input, limit=3)
                        assoc_sources = set()
                        for a in assoc_list:
                            try:
                                assoc_sources.add(getattr(a, 'source_concept', getattr(a, 'concept', None)) or getattr(a, 'name', None))
                            except Exception:
                                continue
                        for cand in candidate_responses:
                            try:
                                if cand.get('source') in assoc_sources:
                                    cand['score'] = cand.get('score', 0) + 1.5
                            except Exception:
                                pass
                    except Exception:
                        pass
        except Exception:
            pass

        # Sort candidates by score
        candidate_responses.sort(key=lambda x: x.get('score', 0), reverse=True)

        # Temporal continuity refinement if available - use retrieve_relevant_pathways to guide selection
        try:
            if self.temporal_system and hasattr(self.temporal_system, 'retrieve_relevant_pathways'):
                try:
                    pathways = self.temporal_system.retrieve_relevant_pathways(user_input, limit=3)
                    pathway_sources = set()
                    for p in pathways:
                        try:
                            related = getattr(p, 'related_concepts', None) or getattr(p, 'concepts', None) or []
                            for item in related:
                                pathway_sources.add(item)
                        except Exception:
                            continue
                    refined = []
                    for cand in candidate_responses[:6]:
                        try:
                            score = cand.get('score', 0)
                            if cand.get('source') in pathway_sources:
                                score += 1.0
                            refined.append({'text': cand.get('text'), 'score': score, 'source': cand.get('source'), 'style': cand.get('style')})
                        except Exception:
                            refined.append(cand)
                    candidate_responses = refined
                except Exception:
                    pass
        except Exception:
            pass

        # Final selection respecting response_style and brevity
        final = candidate_responses[0]
        style = final.get('style', 'concise')
        text = final.get('text', '')
        if style == 'concise' and len(text) > 300:
            text = text.split('. ')[0] + '.'
        return text

