```javascript
// ProEdit App JS

// DOM Elements
const modeButtons = document.querySelectorAll('.mode-btn');
const uploadBtn = document.querySelector('.upload-btn');
const imageInput = document.getElementById('imageInput');
const canvasContainer = document.querySelector('.canvas-container');
const canvas = document.createElement('canvas');
const overlayCanvas = document.createElement('canvas');
const ctx = canvas.getContext('2d');
const overlayCtx = overlayCanvas.getContext('2d');
const selectionInfo = document.querySelector('.selection-info');
const livePreview = document.querySelector('.live-preview');
const liveCtx = livePreview.getContext('2d');
const progressFill = document.querySelector('.progress-fill');

let currentMode = 'extract';
let uploadedImage = null;
let selection = null;
let zoom = 1;
let undoStack = [];
let redoStack = [];

// Initialize Canvas
canvasContainer.appendChild(canvas);
canvasContainer.appendChild(overlayCanvas);
canvas.width = canvasContainer.clientWidth;
canvas.height = canvasContainer.clientHeight;
overlayCanvas.width = canvas.width;
overlayCanvas.height = canvas.height;

// Mode Switching
modeButtons.forEach(btn => {
    btn.addEventListener('click', () => {
        modeButtons.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        currentMode = btn.dataset.mode;
        updateStatus();
    });
});

// Upload Image
uploadBtn.addEventListener('click', () => imageInput.click());
imageInput.addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (file) loadImage(file);
});

// Drag & Drop Upload
canvasContainer.addEventListener('dragover', e => e.preventDefault());
canvasContainer.addEventListener('drop', e => {
    e.preventDefault();
    if (e.dataTransfer.files.length) loadImage(e.dataTransfer.files[0]);
});

// Load Image
function loadImage(file) {
    const reader = new FileReader();
    reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
            uploadedImage = img;
            resetCanvas();
            drawCanvas();
        };
        img.src = e.target.result;
    };
    reader.readAsDataURL(file);
}

// Reset Canvas
function resetCanvas() {
    zoom = 1;
    undoStack = [];
    redoStack = [];
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    overlayCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
}

// Draw Canvas
function drawCanvas() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    if (uploadedImage) {
        const imgWidth = uploadedImage.width * zoom;
        const imgHeight = uploadedImage.height * zoom;
        const x = (canvas.width - imgWidth) / 2;
        const y = (canvas.height - imgHeight) / 2;
        ctx.drawImage(uploadedImage, x, y, imgWidth, imgHeight);
        updateLivePreview(x, y, imgWidth, imgHeight);
    }
}

// Update Live Preview
function updateLivePreview(x, y, width, height) {
    liveCtx.clearRect(0, 0, livePreview.width, livePreview.height);
    liveCtx.drawImage(canvas, x, y, width, height, 0, 0, livePreview.width, livePreview.height);
}

// Canvas Overlay for Selection
let isDragging = false;
let startX, startY;

overlayCanvas.addEventListener('mousedown', e => {
    isDragging = true;
    const rect = overlayCanvas.getBoundingClientRect();
    startX = e.clientX - rect.left;
    startY = e.clientY - rect.top;
});

overlayCanvas.addEventListener('mousemove', e => {
    if (!isDragging) return;
    const rect = overlayCanvas.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const width = mouseX - startX;
    const height = mouseY - startY;

    overlayCtx.clearRect(0, 0, overlayCanvas.width, overlayCanvas.height);
    overlayCtx.strokeStyle = '#ff6b6b';
    overlayCtx.lineWidth = 2;
    overlayCtx.strokeRect(startX, startY, width, height);

    selectionInfo.innerHTML = `Selection: X:${Math.round(startX)} Y:${Math.round(startY)} W:${Math.round(width)} H:${Math.round(height)}`;
});

overlayCanvas.addEventListener('mouseup', e => {
    isDragging = false;
    const rect = overlayCanvas.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    selection = {
        x: startX,
        y: startY,
        width: mouseX - startX,
        height: mouseY - startY
    };
});

// Floating Toolbar Actions
document.querySelectorAll('.floating-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        switch (btn.id) {
            case 'undoBtn': undo(); break;
            case 'redoBtn': redo(); break;
            case 'zoomInBtn': zoomCanvas(1.1); break;
            case 'zoomOutBtn': zoomCanvas(0.9); break;
            case 'fitBtn': fitCanvas(); break;
        }
    });
});

// Undo / Redo
function undo() {
    if (!undoStack.length) return;
    redoStack.push(canvas.toDataURL());
    const last = undoStack.pop();
    loadDataUrl(last);
}

function redo() {
    if (!redoStack.length) return;
    undoStack.push(canvas.toDataURL());
    const last = redoStack.pop();
    loadDataUrl(last);
}

function loadDataUrl(dataUrl) {
    const img = new Image();
    img.onload = () => {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    };
    img.src = dataUrl;
}

// Zoom / Fit
function zoomCanvas(factor) {
    zoom *= factor;
    drawCanvas();
}

function fitCanvas() {
    if (!uploadedImage) return;
    const hRatio = canvas.width / uploadedImage.width;
    const vRatio = canvas.height / uploadedImage.height;
    zoom = Math.min(hRatio, vRatio);
    drawCanvas();
}

// Update Status Bar
function updateStatus() {
    const modeStatus = document.querySelector('.mode-status');
    modeStatus.textContent = `Mode: ${currentMode.charAt(0).toUpperCase() + currentMode.slice(1)}`;
}

// Simulate Progress Bar
function simulateProgress(percent) {
    progressFill.style.width = `${percent}%`;
}

// Initial Status
updateStatus();
